 namespace WPAICG\Vector; if (!defined('ABSPATH')) { exit; } class AIPKit_Vector_Store_Registry { const OPTION_NAME = 'aipkit_vector_stores_registry'; private const PROVIDER_CACHE_CONFIG = [ 'Pinecone' => [ 'option' => 'aipkit_pinecone_index_list', 'model_key' => 'PineconeIndexes', ], 'Qdrant' => [ 'option' => 'aipkit_qdrant_collection_list', 'model_key' => 'QdrantCollections', ], 'Chroma' => [ 'option' => 'aipkit_chroma_collection_list', 'model_key' => 'ChromaCollections', ], ]; public static function get_all_registered_stores(): array { return get_option(self::OPTION_NAME, []); } public static function get_registered_stores_by_provider(string $provider): array { $all_stores = self::get_all_registered_stores(); return $all_stores[$provider] ?? []; } public static function update_registered_stores_for_provider(string $provider, array $stores_list): void { self::replace_provider_cache($provider, $stores_list); } public static function replace_provider_cache(string $provider, array $stores_list): array { $provider = self::normalize_provider_name($provider); if ($provider === '') { return []; } $normalized_stores = self::normalize_stores_for_provider($provider, $stores_list); $all_stores = self::get_all_registered_stores(); $all_stores[$provider] = $normalized_stores; update_option(self::OPTION_NAME, $all_stores, false); wp_cache_delete(self::OPTION_NAME, 'options'); self::persist_provider_option_cache($provider, $normalized_stores); self::clear_provider_runtime_cache($provider); return $normalized_stores; } public static function add_registered_store(string $provider, array $store_data): void { $provider = self::normalize_provider_name($provider); $store_data = self::normalize_store_for_provider($provider, $store_data); if ($provider === '' || empty($store_data)) { return; } $provider_stores = self::get_registered_stores_by_provider($provider); $provider_stores = self::normalize_stores_for_provider($provider, $provider_stores); $found = false; foreach ($provider_stores as $key => $existing_store) { if (self::store_matches_id($existing_store, (string) $store_data['id'])) { $provider_stores[$key] = array_merge($existing_store, $store_data, ['provider' => $provider]); $found = true; break; } } if (!$found) { $provider_stores[] = $store_data; } self::replace_provider_cache($provider, $provider_stores); } public static function remove_registered_store(string $provider, string $store_id): void { $provider = self::normalize_provider_name($provider); $store_id = trim($store_id); if ($provider === '' || $store_id === '') { return; } $provider_stores = self::get_registered_stores_by_provider($provider); if (empty($provider_stores)) { $provider_stores = self::get_provider_option_cache($provider); } $updated_provider_stores = array_values(array_filter( self::normalize_stores_for_provider($provider, $provider_stores), static function (array $store) use ($store_id): bool { return !self::store_matches_id($store, $store_id); } )); self::replace_provider_cache($provider, $updated_provider_stores); } public static function clear_registered_stores(?string $provider = null): void { if ($provider === null) { delete_option(self::OPTION_NAME); wp_cache_delete(self::OPTION_NAME, 'options'); foreach (array_keys(self::PROVIDER_CACHE_CONFIG) as $provider_name) { self::persist_provider_option_cache($provider_name, []); self::clear_provider_runtime_cache($provider_name); } } else { $provider = self::normalize_provider_name($provider); $all_stores = self::get_all_registered_stores(); if (isset($all_stores[$provider])) { unset($all_stores[$provider]); update_option(self::OPTION_NAME, $all_stores, false); wp_cache_delete(self::OPTION_NAME, 'options'); } self::persist_provider_option_cache($provider, []); self::clear_provider_runtime_cache($provider); } } private static function normalize_provider_name(string $provider): string { $provider = strtolower(trim($provider)); $map = [ 'openai' => 'OpenAI', 'pinecone' => 'Pinecone', 'qdrant' => 'Qdrant', 'chroma' => 'Chroma', ]; return $map[$provider] ?? ''; } private static function normalize_stores_for_provider(string $provider, array $stores_list): array { $normalized = []; $seen = []; foreach ($stores_list as $store_data) { $store = self::normalize_store_for_provider($provider, $store_data); if (empty($store)) { continue; } $id = (string) $store['id']; if (isset($seen[$id])) { $normalized[$seen[$id]] = array_merge($normalized[$seen[$id]], $store); continue; } $seen[$id] = count($normalized); $normalized[] = $store; } return $normalized; } private static function normalize_store_for_provider(string $provider, $store_data): array { if ($provider === '') { return []; } if (is_string($store_data) || is_numeric($store_data)) { $store_data = [ 'id' => (string) $store_data, 'name' => (string) $store_data, ]; } if (!is_array($store_data)) { return []; } $store_data['provider'] = $provider; $name = isset($store_data['name']) && is_scalar($store_data['name']) ? trim((string) $store_data['name']) : ''; $id = isset($store_data['id']) && is_scalar($store_data['id']) ? trim((string) $store_data['id']) : ''; if ($provider === 'Chroma') { $collection_name = isset($store_data['collection_name']) && is_scalar($store_data['collection_name']) ? trim((string) $store_data['collection_name']) : ''; if ($name === '' && $collection_name !== '') { $name = $collection_name; } } if ($id === '' && $name !== '') { $id = $name; } if ($name === '' && $id !== '') { $name = $id; } if ($id === '') { return []; } $store_data['id'] = $id; if ($name !== '') { $store_data['name'] = $name; } return $store_data; } private static function get_provider_option_cache(string $provider): array { $config = self::PROVIDER_CACHE_CONFIG[$provider] ?? null; if (empty($config['option'])) { return []; } $cached = get_option((string) $config['option'], []); return is_array($cached) ? $cached : []; } private static function persist_provider_option_cache(string $provider, array $stores): void { $config = self::PROVIDER_CACHE_CONFIG[$provider] ?? null; if (empty($config['option'])) { return; } $option_name = (string) $config['option']; update_option($option_name, $stores, 'no'); wp_cache_delete($option_name, 'options'); } private static function clear_provider_runtime_cache(string $provider): void { $config = self::PROVIDER_CACHE_CONFIG[$provider] ?? null; if (!empty($config['model_key'])) { delete_transient('aipkit_' . strtolower((string) $config['model_key']) . '_models_cache'); } if (class_exists('\\WPAICG\\AIPKit_Providers') && method_exists('\\WPAICG\\AIPKit_Providers', 'clear_model_caches')) { \WPAICG\AIPKit_Providers::clear_model_caches(); } } private static function store_matches_id(array $store, string $store_id): bool { $candidates = [ $store['id'] ?? '', $store['name'] ?? '', $store['chroma_id'] ?? '', $store['collection_name'] ?? '', ]; foreach ($candidates as $candidate) { if (is_scalar($candidate) && (string) $candidate === $store_id) { return true; } } return false; } } 